import logo from './logo.svg';
import './App.css';
import React, { Component, useRef, useEffect } from 'react';
import { BrowserRouter, Route, Switch } from 'react-router-dom';
import Evaluation from './components/Eval';
import About from './components/About';
import Shop from './components/Shop';
import Cardiology from './components/Cardiology'
import EvalForm from './components/Eval/EvalForm'
import UploadSchedule from './components/UploadCardiology'
import EvalNew from './components/Eval/EvalNew'
import EvalReport from './components/Eval/EvalReport'
import CareWebPage from './components/Page/CareWebPage'
import Booking from './components/Room/Room'
import RoomAdmin from './components/Room/RoomAdmin'
import EvalStatus from './components/Eval/EvalStatus'
import GetTriage from './components/Triage/Triage'
import Scheduler from './components/Scheduler/Scheduler'
import AssignSchedule from './components/Scheduler/AssignSchedule'
import UploadOff from './components/AmionOff/Upload'
import AmionOff from './components/AmionOff/Calendar'
import Voalte from './components/Voalte/GetUser'
import UploadPayroll from './components/Payroll/Upload'
import UploadPayrollADR from './components/Payroll/UploadADR'
import VoalteAttending from './components/Voalte/Attending'
import VoalteDevice from './components/Voalte/GetDevice'
import UploadVoalteFamily from './components/VoalteFamily/Upload'
import VoalteFamilyReport from './components/VoalteFamily/Report'
import UploadEducation from './components/Education/Upload'
import ReportEducation from './components/Education/Report'
import WorkflowActivation from './components/Activation/responsive'
import SchedulerEmp from './components/Schedule/EmployeeAdmin'
import GetScheduler from './components/Schedule/GetSchedule'
import GetBlock from './components/Schedule/GetBlock'
import CyberAdmin from './components/CyberRaptor/CyberAdmin'
import CyberRaptor from './components/CyberRaptor/CyberRaptor'
import Algorithm from './components/CyberRaptor/GetAlgorithm'
import Main from './components/Main/Main'
import Canvas from './components/Canvas/canvas'

function App() {
  /*
  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <p>
          Edit <code>src/App.js</code> and save to reload.
        </p>
        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Learn React
        </a>
      </header>
    </div>
  );
  */


  const canvas = useRef();
  let ctx = null;

  // initialize the canvas context
  useEffect(() => {
    // dynamically assign the width and height to canvas
    const canvasEle = canvas.current;
    //canvasEle.width = canvasEle.clientWidth;
    //canvasEle.height = canvasEle.clientHeight;

    // get context of the canvas
    ctx = canvasEle.getContext("2d");
  }, []);

  useEffect(() => {
    drawLine({ x: 20, y: 20, x1: 20, y1: 100 });

    drawLine({ x: 50, y: 50, x1: 200, y1: 100 }, { color: 'red' });

    drawLine({ x: 300, y: 250, x1: 260, y1: 70 }, { color: 'green', width: 5 });

    drawLine({ x: 70, y: 240, x1: 160, y1: 120 }, { color: 'blue' });
  }, []);

  // draw a line
  const drawLine = (info, style = {}) => {
    const { x, y, x1, y1 } = info;
    const { color = 'black', width = 1 } = style;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x1, y1);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.stroke();
  }



  return (
    <main>
        <Switch>
        <Route path="/canvas" component={Canvas}/>

        <Route path="/algorithm" component={Algorithm}/>
          <Route path="/cyberraptor" component={CyberRaptor}/>
          <Route path="/cyberadmin" component={CyberAdmin}/>
          <Route path="/button" component={WorkflowActivation}/>
          <Route path="/get_schedule" component={GetScheduler}/>
          <Route path="/schedule_emp" component={SchedulerEmp}/>
          <Route path="/block_schedule" component={GetBlock}/>
          <Route path="/booking" component={Booking}/>
          <Route path="/roomadmin" component={RoomAdmin}/>
          <Route path="/eval" component={EvalNew}/>
          <Route path="/evalreport" component={EvalReport}/>



          <Route path="/educationReport" component={ReportEducation}/>
      <Route path="/familyReport" component={VoalteFamilyReport}/>
          <Route path="/uploadfamily" component={UploadVoalteFamily}/>
          <Route path="/uploadeducation" component={UploadEducation}/>
        <Route path="/cardiology" component={Cardiology}/>
          <Route path="/" component={Main} exact />
          <Route Path="/VoalteDevice" component={VoalteDevice}/>
          <Route Path="/Voalte" component={Voalte}/>
          <Route Path="/VoalteGroup" component={VoalteAttending}/>
          <Route path="/evalform" component={EvalForm}/>
          <Route path="/about" component={About} />
          <Route path="/shop" component={Shop} />
          <Route path="/upload" component={UploadSchedule}/>

          <Route path="/paging" component={CareWebPage}/>

          <Route path="/evalstatus" component={EvalStatus}/>
          <Route path="/triage" component={GetTriage}/>
          <Route path="/scheduler" component={Scheduler}/>
          <Route path="/assignSchedule" component={AssignSchedule}/>
          <Route path="/uploadOff" component={UploadOff}/>
          <Route path="/AmionOff" component={AmionOff}/>
          <Route path="/uploadPayroll" component={UploadPayroll}/>
          <Route path="/uploadPayrollADR" component={UploadPayrollADR}/>

          <Route component={Error} />
        </Switch>
    </main>
  )
}

export default App;
